ALTER TABLE shops DISABLE ROW LEVEL SECURITY;
ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name, address = EXCLUDED.address, city = EXCLUDED.city, country = EXCLUDED.country,
  latitude = EXCLUDED.latitude, longitude = EXCLUDED.longitude, brand_id = EXCLUDED.brand_id,
  is_active = EXCLUDED.is_active, logo_url = EXCLUDED.logo_url, category = EXCLUDED.category;
ALTER TABLE shops ENABLE ROW LEVEL SECURITY;